changeSet.sql:
UPDATE chess_games SET white_player_uuid = (
    SELECT uuid FROM chess_users WHERE chess_users.id = chess_games.white_player_id
) WHERE white_player_id IS NOT NULL;

UPDATE chess_games SET black_player_uuid = (
    SELECT uuid FROM chess_users WHERE chess_users.id = chess_games.black_player_id
) WHERE black_player_id IS NOT NULL;

UPDATE chess_games SET draw_offered_by_uuid = (
    SELECT uuid FROM chess_users WHERE chess_users.id = chess_games.draw_offered_by
) WHERE draw_offered_by IS NOT NULL;
